const initialState = { items: [], total: 0 };

function cartReducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM': {
      const existing = state.items.find(item => item.id === action.payload.id);
      let newItems;
      if (existing) {
        newItems = state.items.map(item =>
          item.id === action.payload.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      } else {
        newItems = [...state.items, { ...action.payload, quantity: 1 }];
      }
      const newTotal = newItems.reduce((sum, item) => sum + item.price * item.quantity, 0);
      return { items: newItems, total: newTotal };
    }
    case 'REMOVE_ITEM':
      const filtered = state.items.filter(item => item.id !== action.payload);
      const total = filtered.reduce((sum, item) => sum + item.price * item.quantity, 0);
      return { items: filtered, total };
    case 'UPDATE_QUANTITY':
      const updated = state.items.map(item =>
        item.id === action.payload.id
          ? { ...item, quantity: Math.max(0, action.payload.quantity) }
          : item
      ).filter(item => item.quantity > 0);
      const newTotalCalc = updated.reduce((sum, item) => sum + item.price * item.quantity, 0);
      return { items: updated, total: newTotalCalc };
    case 'CLEAR_CART':
      return { items: [], total: 0 };
    default:
      return state;
  }
}
